// Filter and format check-in/check-out notifications
const hoy = $('Get Fechas Chile').first().json.hoy;
const reservas = $input.all().flatMap(i => Array.isArray(i.json) ? i.json : [i.json]);

const checkinsHoy = [];
const checkinsManana = [];
const checkoutsHoy = [];
const checkoutsManana = [];

const hoyDate = new Date(hoy + 'T12:00:00-03:00');
const mananaDate = new Date(hoyDate);
mananaDate.setDate(mananaDate.getDate() + 1);
const fmt = d => d.toISOString().split('T')[0];
const hoyStr = fmt(hoyDate);
const mananaStr = fmt(mananaDate);

for (const r of reservas) {
  const cin = (r.checkInDate || '').slice(0, 10);
  const cout = (r.checkOutDate || '').slice(0, 10);
  const guest = r.guestsDetails?.list?.[0]?.name || 'Sin nombre';
  const guests = r.guests || 1;
  const listing = r._idlisting || '?';

  if (cin === hoyStr) {
    checkinsHoy.push({ listing, guest, guests, cout, cin });
  } else if (cin === mananaStr) {
    checkinsManana.push({ listing, guest, guests, cout, cin });
  }

  if (cout === hoyStr) {
    checkoutsHoy.push({ listing, guest, cout });
  } else if (cout === mananaStr) {
    checkoutsManana.push({ listing, guest, cout });
  }
}

const result = { checkinsHoy, checkinsManana, checkoutsHoy, checkoutsManana, hoy: hoyStr, manana: mananaStr };

// Build messages
const msgs = [];

if (checkinsHoy.length > 0) {
  let txt = '*🟢 Check-in hoy ' + hoyStr.split('-').reverse().join('-') + '*\n';
  for (const c of checkinsHoy) txt += `• ${c.listing} | ${c.guest} | ${c.guests} pers | hasta ${c.cout.split('-').reverse().join('-')}\n`;
  msgs.push({ text: txt, type: 'checkin_hoy' });
}

if (checkoutsHoy.length > 0) {
  let txt = '*🔴 Check-out hoy ' + hoyStr.split('-').reverse().join('-') + ' (aseo)*\n';
  for (const c of checkoutsHoy) txt += `• ${c.listing} | ${c.guest} | aseo requerido\n`;
  msgs.push({ text: txt, type: 'aseo_hoy' });
}

if (checkinsManana.length > 0) {
  let txt = '*🟡 Check-in mañana ' + mananaStr.split('-').reverse().join('-') + '*\n';
  for (const c of checkinsManana) txt += `• ${c.listing} | ${c.guest} | ${c.guests} pers\n`;
  msgs.push({ text: txt, type: 'checkin_manana' });
}

if (checkoutsManana.length > 0) {
  let txt = '*🟠 Aseo mañana ' + mananaStr.split('-').reverse().join('-') + '*\n';
  for (const c of checkoutsManana) txt += `• ${c.listing} | ${c.guest}\n`;
  msgs.push({ text: txt, type: 'aseo_manana' });
}

return msgs.length > 0 ? msgs : [{ text: null, type: 'empty' }];
